/**
 * Factory function that creates a fresh {@link DeliveriesRepository} instance.
 *
 * Opens (or reuses, depending on the driver implementation) a database
 * connection and wraps it in a new repository object.  Use this when you need
 * an isolated instance — most commonly in tests.
 *
 * For production code, prefer {@link getDeliveriesRepository} which returns a
 * shared singleton.
 *
 * @param isTest - Pass `true` to connect to the test database; defaults to `false`
 * @returns Promise resolving to a new {@link DeliveriesRepository} instance
 * @throws {DatabaseError} If the database connection cannot be established
 *
 * @example
 * ```typescript
 * // Production — new isolated instance
 * const repo = await createDeliveriesRepository();
 *
 * // Test — connects to the in-memory/test DB
 * const testRepo = await createDeliveriesRepository(true);
 * ```
 */
export async function createDeliveriesRepository(
  isTest: boolean = false,
): Promise<DeliveriesRepository> {
  const db = await getDatabase(isTest);
  return new DeliveriesRepository(db);
}

// Singleton instance for default production usage.
let deliveriesRepo: DeliveriesRepository | null = null;

/**
 * Returns a shared {@link DeliveriesRepository} singleton for production use, or a
 * fresh instance when running in a test environment.
 *
 * The singleton is initialised lazily on the first call and reused on subsequent
 * calls, avoiding repeated connection overhead.  In test environments (detected via
 * `NODE_ENV === 'test'` or `VITEST === 'true'`), a new instance is always returned
 * so that tests remain isolated.
 *
 * @param isTest - Explicitly request the test database; defaults to `false`; the
 *   function also auto-detects the test environment via environment variables
 * @returns Promise resolving to the {@link DeliveriesRepository} instance
 * @throws {DatabaseError} If the database connection cannot be established on first
 *   initialisation
 *
 * @example
 * ```typescript
 * // Get the shared production singleton
 * const repo = await getDeliveriesRepository();
 * const all = await repo.findAll();
 *
 * // Get an isolated test instance (also returned automatically in Vitest)
 * const testRepo = await getDeliveriesRepository(true);
 * ```
 */
export async function getDeliveriesRepository(
  isTest: boolean = false,
): Promise<DeliveriesRepository> {
  const isTestEnv = isTest || process.env.NODE_ENV === 'test' || process.env.VITEST === 'true';
  if (isTestEnv) {
    return createDeliveriesRepository(true);
  }
  if (!deliveriesRepo) {
    deliveriesRepo = await createDeliveriesRepository(false);
  }
  return deliveriesRepo;
}
